import React, { useState } from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';

// Pages
import Dashboard from './pages/Dashboard';
import Login from './pages/Login';
import UserInputPage from './pages/UserInputPage';
import Profile from './pages/Profile';
import SkillsPage from './pages/SkillsPage';
import Predictions from './pages/Predictions';
import AIMentor from './pages/AIMentor';
import SkillDetails from './pages/SkillDetails';

function App() {
  const [isAuthenticated, setIsAuthenticated] = useState(false);

  return (
    <Router>
      <div className="min-h-screen">
        <Routes>
          <Route path="/login" element={<Login setIsAuthenticated={setIsAuthenticated} />} />
          <Route 
            path="/" 
            element={isAuthenticated ? <UserInputPage /> : <Login setIsAuthenticated={setIsAuthenticated} />} 
          />
          <Route path="/input" element={isAuthenticated ? <UserInputPage /> : <Login setIsAuthenticated={setIsAuthenticated} />} />
          <Route path="/dashboard" element={isAuthenticated ? <Dashboard /> : <Login setIsAuthenticated={setIsAuthenticated} />} />
          <Route path="/profile" element={<Profile />} />
          <Route path="/skills" element={<SkillsPage />} />
          <Route path="/skill/:id" element={<SkillDetails />} />
          <Route path="/predictions" element={<Predictions />} />
          <Route path="/mentor" element={<AIMentor />} />
        </Routes>
      </div>
    </Router>
  );
}

export default App;
